-- Current Pokemon Champions roster mapping for your existing `pokemon` table.
-- This is idempotent:
-- 1. inserts `pokemon champions` into `game`
-- 2. links all mapped Champions pokemon into `pokemon_game`
-- 3. skips anything already linked
--
-- Note: this matches against the pokemon names that already exist in your seed.
-- Champions forms/megas that are not yet present in `pokemon` will be skipped automatically.

WITH champions_game AS (
  INSERT INTO game (name)
  VALUES ('Pokemon Champions')
  ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name
  RETURNING id
),
