INSERT INTO pokemon_game (pokemon_id, game_id)
SELECT p.id, g.id
FROM champions_pokemon cp
JOIN pokemon p
  ON p.name = cp.name
CROSS JOIN champions_game g
WHERE NOT EXISTS (
  SELECT 1
  FROM pokemon_game pg
  WHERE pg.pokemon_id = p.id
    AND pg.game_id = g.id
);


-- FireRed / LeafGreen roster mapping.
-- This is idempotent:
-- 1. inserts `fire_red` and `leaf_green` into `game`
-- 2. links the shared Kanto roster to both games
-- 3. links version exclusives only to their matching game
-- 4. skips anything already linked

WITH frlg_games AS (
  INSERT INTO game (name)
  VALUES ('Fire Red'), ('Leaf Green')
  ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name
  RETURNING id, name
),
fire_red_exclusive(name) AS (
  VALUES
    ('ekans'),
    ('arbok'),
    ('oddish'),
    ('gloom'),
    ('vileplume'),
    ('psyduck'),
    ('golduck'),
    ('growlithe'),
    ('arcanine'),
    ('shellder'),
    ('cloyster'),
    ('electabuzz'),
    ('scyther'),
    ('bellossom'),
    ('wooper'),
    ('quagsire'),
    ('murkrow'),
    ('qwilfish'),
    ('scizor'),
    ('delibird'),
    ('skarmory'),
    ('elekid'),
    ('deoxys-attack')
),
leaf_green_exclusive(name) AS (
  VALUES
    ('sandshrew'),
    ('sandslash'),
    ('vulpix'),
    ('ninetales'),
    ('bellsprout'),
    ('weepinbell'),
    ('victreebel'),
    ('slowpoke'),
    ('slowbro'),
    ('staryu'),
    ('starmie'),
    ('magmar'),
    ('pinsir'),
    ('marill'),
    ('azumarill'),
    ('slowking'),
    ('misdreavus'),
    ('sneasel'),
    ('remoraid'),
    ('octillery'),
    ('mantine'),
    ('magby'),
    ('azurill'),
    ('deoxys-defense')
),
shared_kanto_pokemon AS (
  SELECT p.id
  FROM pokemon p
  WHERE p.artwork_id BETWEEN 1 AND 151
    AND p.name <> 'mew'
    AND NOT EXISTS (
      SELECT 1
      FROM fire_red_exclusive fre
      WHERE fre.name = p.name
    )
    AND NOT EXISTS (
      SELECT 1
      FROM leaf_green_exclusive lge
      WHERE lge.name = p.name
    )
),
frlg_pokemon_game AS (
  SELECT skp.id AS pokemon_id, fg.id AS game_id
  FROM shared_kanto_pokemon skp
  CROSS JOIN frlg_games fg

  UNION

  SELECT p.id AS pokemon_id, fg.id AS game_id
  FROM fire_red_exclusive fre
  JOIN pokemon p
    ON p.name = fre.name
  JOIN frlg_games fg
    ON fg.name = 'fire_red'

  UNION

  SELECT p.id AS pokemon_id, fg.id AS game_id
  FROM leaf_green_exclusive lge
  JOIN pokemon p
    ON p.name = lge.name
  JOIN frlg_games fg
    ON fg.name = 'leaf_green'
)
INSERT INTO pokemon_game (pokemon_id, game_id)
SELECT fpg.pokemon_id, fpg.game_id
FROM frlg_pokemon_game fpg
WHERE NOT EXISTS (
  SELECT 1
  FROM pokemon_game pg
  WHERE pg.pokemon_id = fpg.pokemon_id
    AND pg.game_id = fpg.game_id
);
